          <Datos />
        </div>

        <button>
          <img src={Der} className="w-[30vh] h-auto" />
        </button>
      </div>

      {/* WAVE abajo SIEMPRE */}
      <div className="absolute bottom-0 left-0 w-full">
        <Wave />
      </div>

    </section>
  );
};
